INSERT INTO offmarket.business_signals (business_id, layer, signal_key, direction, evidence, source, source_url, observed_at) VALUES ('e9b2469f-cb0f-5bc9-8a69-b22ed62d1a2d', 2, 'sellability_quality', 'positive', 'Sub-trade: commercial; recurring revenue: STRONG; verification: Founded by Wayne Awtrey. Wayne died 2003. Catherine (widow) has run it since. Annual preventive maintenance programs. Long-tenured widow-led shop.', 'website_fetch_plus_search', 'https://texasroof.com/', '2026-05-16');
INSERT INTO offmarket.business_signals (business_id, layer, signal_key, direction, evidence, source, source_url, observed_at) VALUES ('e9b2469f-cb0f-5bc9-8a69-b22ed62d1a2d', 3, 'successor_check_live_fetch', 'positive', 'Catherine Awtrey (President/Owner, took over 2003 = 23 yrs). Address: 728 Lingco Drive, Richardson TX 75081 (Dallas suburb, NOT Houston). Wayne Awtrey founded 1996; died 2003. Catherine is career-changer widow (Blair TV → real estate → image consulting → roofing). D CEO Magazine ''Women Who Built Dallas'' June 2019. NTRCA Industry Leader of the Year 2020. NO Awtrey children on team page. Senior management team: Mike Cieri (CFO), Danielle Begley (VP Business Ops), John Wayne Whitten (Senior Advisor + QA/QC Manager), Brett Norvell (Director of Ops), Ian Sellers (Service Manager), Dustin Daniel (Chief Estimator), Ana Ledbetter (Service Coordinator). Commercial preventive maintenance contracts = strong recurring revenue. Annual maintenance program. Firm-bid pricing. Service hours + 24/7 service (972-272-7663 office, 972-231-8350 service).', 'live_website_fetch', 'https://texasroof.com/company/our-team/ + https://texasroof.com/catherine-awtrey-recognized-in-d-ceo-magazine/', '2026-05-16');
